// Validate that the inbound payload has all required fields per contracts/inbound-event.schema.json
const required = ['schema_version', 'event_id', 'correlation_id', 'source', 'type', 'occurred_at'];

for (const item of $input.all()) {
  const ev = item.json;
  const missing = required.filter(f => !ev[f]);
  if (missing.length > 0) {
    throw new Error(`Inbound event validation FAILED. Missing fields: ${missing.join(', ')}. Received: ${JSON.stringify(Object.keys(ev))}`);
  }
  if (!['message', 'command', 'scheduled', 'data_snapshot'].includes(ev.type)) {
    throw new Error(`Inbound event validation FAILED. Unknown type: "${ev.type}". Must be one of: message, command, scheduled, data_snapshot.`);
  }
}

// Pass everything through unchanged
return $input.all();

// Build the ai-output JSON from the AI Agent's response.
// The agent outputs a JSON string; we parse, validate, and normalize it.

const results = [];

for (const item of $input.all()) {
  const inbound = item.json;
  let aiOutput;

  // The AI Agent's response is in .output
  const rawOutput = (inbound.output !== undefined) ? inbound.output : (inbound.text || '');

  try {
    // Extract JSON from the agent's response (may be wrapped in markdown or have leading/trailing text)
    let jsonStr = String(rawOutput).trim();

    // Strip markdown code fences if present
    const fenceMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (fenceMatch) {
      jsonStr = fenceMatch[1].trim();
    }

    aiOutput = JSON.parse(jsonStr);
  } catch (e) {
    // If parsing fails, use a deny fallback
    aiOutput = {
      schema_version: "1.0",
      correlation_id: inbound.correlation_id || '',
      path: "deny",
      summary: "Failed to parse AI agent output as valid JSON.",
      guardrail: {
        triggered: true,
        rule: "parse_error",
        message: "The model did not return valid JSON. Raw: " + String(rawOutput).substring(0, 200)
      },
      confidence: 0
    };
  }

  // Enforce correlation_id echo (contract requirement)
  aiOutput.correlation_id = inbound.correlation_id || aiOutput.correlation_id;

  // Ensure schema_version
  aiOutput.schema_version = aiOutput.schema_version || "1.0";

  // Default path to deny if missing
  if (!['alpha', 'beta', 'gamma', 'deny'].includes(aiOutput.path)) {
    aiOutput.path = 'deny';
    aiOutput.summary = aiOutput.summary || 'Agent returned invalid path.';
    aiOutput.guardrail = aiOutput.guardrail || { triggered: true, rule: 'invalid_path', message: 'Model output missing valid path.' };
  }

  // Ensure summary exists
  aiOutput.summary = aiOutput.summary || `Routed to path: ${aiOutput.path}`;

  // Normalize reply
  if (aiOutput.reply && !aiOutput.reply.format) {
    aiOutput.reply.format = 'markdown';
  }

  // Ensure actions is an array
  if (!Array.isArray(aiOutput.actions)) {
    aiOutput.actions = [];
  }

  // Ensure guardrail object
  if (!aiOutput.guardrail) {
    aiOutput.guardrail = { triggered: false };
  }

  // Ensure confidence
  if (typeof aiOutput.confidence !== 'number') {
    aiOutput.confidence = aiOutput.path === 'deny' ? 1.0 : 0.8;
  }

  results.push({
    json: {
      // Inbound event fields (propagated for DB logging and response)
      event_id: inbound.event_id,
      correlation_id: inbound.correlation_id,
      source: inbound.source,
      type: inbound.type,
      occurred_at: inbound.occurred_at,
      actor: inbound.actor,
      channel: inbound.channel,
      text: inbound.text,
      data: inbound.data,
      attachments: inbound.attachments,
      metadata: inbound.metadata,
      raw: inbound.raw,

      // AI output fields (flattened for easy access by spokes)
      ai_schema_version: aiOutput.schema_version,
      ai_path: aiOutput.path,
      ai_summary: aiOutput.summary,
      ai_reply_text: aiOutput.reply ? aiOutput.reply.text : null,
      ai_reply_format: aiOutput.reply ? (aiOutput.reply.format || 'markdown') : null,
      ai_actions: aiOutput.actions,
      ai_guardrail_triggered: aiOutput.guardrail.triggered || false,
      ai_guardrail_rule: aiOutput.guardrail.rule || null,
      ai_guardrail_message: aiOutput.guardrail.message || null,
      ai_confidence: aiOutput.confidence,

      // Full objects for JSONB storage
      inbound_event: JSON.parse(JSON.stringify(inbound)),
      ai_output: aiOutput
    }
  });
}

return results;

// Prepare a safely-escaped SQL INSERT string for the downstream Postgres node.
// JavaScript-side escaping prevents SQL injection before the query reaches Postgres.

const results = [];

for (const item of $input.all()) {
  const d = item.json;

  const esc = (s) => String(s || '').replace(/'/g, "''").replace(/\\/g, "\\\\").substring(0, 4000);
  const toJsonb = (obj) => {
    if (!obj) return 'null::jsonb';
    return "'" + JSON.stringify(obj).replace(/'/g, "''") + "'::jsonb";
  };

  const dbActor = (d.actor && d.actor.display_name) ? "'" + esc(d.actor.display_name) + "'" : 'NULL';
  const dbChannel = (d.channel && d.channel.name) ? "'" + esc(d.channel.name) + "'" : 'NULL';
  const dbText = d.text ? "'" + esc(d.text) + "'" : 'NULL';
  const dbSummary = d.ai_summary ? "'" + esc(d.ai_summary) + "'" : 'NULL';
  const dbStatus = (d.ai_path === 'deny') ? 'error' : 'logged';

  const sql = [
    'INSERT INTO clone.activity_logs (source, event_type, correlation_id, actor, channel, user_query, ai_summary, inbound_event, ai_output, status)',
    'VALUES (',
    `  '${esc(d.source)}',`,
    `  '${esc(d.type)}',`,
    `  '${esc(d.correlation_id)}'::uuid,`,
    `  ${dbActor},`,
    `  ${dbChannel},`,
    `  ${dbText},`,
    `  ${dbSummary},`,
    `  ${toJsonb(d.inbound_event)},`,
    `  ${toJsonb(d.ai_output)},`,
    `  '${dbStatus}'`,
    ')',
    'ON CONFLICT DO NOTHING;'
  ].join('\n');

  results.push({
    json: Object.assign({}, d, { _sql: sql })
  });
}

return results;
